proof_block:
// The ensures clause is `H ==> det_..._equal(...)`, so the per-run
// ensures-conjuncts are *not* free hypotheses inside the body; they only
// become available as path conditions. Bind both runs to short names and
// then drop into an `if H1 && H2 { ... }` branch where the ensures
// becomes a path condition we can chain into `det_..._equal`.
let (rr1, ne1) = r1;
let (rr2, ne2) = r2;

if  // --- per-run ensures, run 1 ---
    post1_netc.my_end_point() == pre_netc.my_end_point()
    && post1_netc.ok() == !(rr1 is Fail)
    && (!(rr1 is Fail)
         ==> (post1_netc.ok()
              && post1_netc.history() == pre_netc.history() + seq!(ne1@)))
    && (rr1 is Timeout ==> ne1@ is TimeoutReceive)
    && (rr1 is Packet
         ==> (ne1@ is Receive
              && rr1.arrow_Packet_cpacket().abstractable()
              && (!(rr1.arrow_Packet_cpacket()@.msg is InvalidMessage)
                   ==> (rr1.arrow_Packet_cpacket()@
                          == abstractify_net_packet_to_sht_packet(ne1@.arrow_Receive_r())
                        && rr1.arrow_Packet_cpacket().msg@
                          == sht_demarshal_data(ne1@.arrow_Receive_r().msg)@))
              && rr1.arrow_Packet_cpacket().dst@ == local_addr@))
    // --- per-run ensures, run 2 ---
    && post2_netc.my_end_point() == pre_netc.my_end_point()
    && post2_netc.ok() == !(rr2 is Fail)
    && (!(rr2 is Fail)
         ==> (post2_netc.ok()
              && post2_netc.history() == pre_netc.history() + seq!(ne2@)))
    && (rr2 is Timeout ==> ne2@ is TimeoutReceive)
    && (rr2 is Packet
         ==> (ne2@ is Receive
              && rr2.arrow_Packet_cpacket().abstractable()
              && (!(rr2.arrow_Packet_cpacket()@.msg is InvalidMessage)
                   ==> (rr2.arrow_Packet_cpacket()@
                          == abstractify_net_packet_to_sht_packet(ne2@.arrow_Receive_r())
                        && rr2.arrow_Packet_cpacket().msg@
                          == sht_demarshal_data(ne2@.arrow_Receive_r().msg)@))
              && rr2.arrow_Packet_cpacket().dst@ == local_addr@))
{
    // Inside the if-branch the per-run ensures are available as path
    // conditions, so the next assertions are provable from them.

    // --- (A) `my_end_point()` agrees across the two posts ---
    // Both posts have `my_end_point() == pre_netc.my_end_point()`.
    assert(post1_netc.my_end_point() == pre_netc.my_end_point());
    assert(post2_netc.my_end_point() == pre_netc.my_end_point());
    assert(post1_netc.my_end_point() == post2_netc.my_end_point());

    // --- (B) `ok()` is pinned to `!is Fail` on each run ---
    assert(post1_netc.ok() == !(rr1 is Fail));
    assert(post2_netc.ok() == !(rr2 is Fail));

    // --- (C) Both runs, when not Fail, append a single ghost event to history ---
    assert(!(rr1 is Fail)
        ==> post1_netc.history() == pre_netc.history() + seq!(ne1@));
    assert(!(rr2 is Fail)
        ==> post2_netc.history() == pre_netc.history() + seq!(ne2@));

    // --- (D) Timeout discriminant propagates to ghost net-event on each run ---
    assert(rr1 is Timeout ==> ne1@ is TimeoutReceive);
    assert(rr2 is Timeout ==> ne2@ is TimeoutReceive);

    // --- (E) Packet branch: dst@ is pinned to `local_addr@`, Receive event,
    //        and (under non-Invalid) the abstracted packet/msg equalities hold.
    assert(rr1 is Packet ==> rr1.arrow_Packet_cpacket().dst@ == local_addr@);
    assert(rr2 is Packet ==> rr2.arrow_Packet_cpacket().dst@ == local_addr@);
    assert(rr1 is Packet ==> ne1@ is Receive);
    assert(rr2 is Packet ==> ne2@ is Receive);

    // Pointwise dst@ agreement on the Packet sub-case (both runs return a Packet).
    if rr1 is Packet && rr2 is Packet {
        assert(rr1.arrow_Packet_cpacket().dst@ == local_addr@);
        assert(rr2.arrow_Packet_cpacket().dst@ == local_addr@);
        assert(rr1.arrow_Packet_cpacket().dst@ == rr2.arrow_Packet_cpacket().dst@);
        assert(ne1@ is Receive);
        assert(ne2@ is Receive);
    }

    // Pointwise Timeout-receive agreement on the Timeout sub-case.
    if rr1 is Timeout && rr2 is Timeout {
        assert(ne1@ is TimeoutReceive);
        assert(ne2@ is TimeoutReceive);
    }

    // Both not-Fail sub-case: the two histories share the prefix `pre_netc.history()`.
    if !(rr1 is Fail) && !(rr2 is Fail) {
        assert(post1_netc.ok());
        assert(post2_netc.ok());
        assert(post1_netc.history() == pre_netc.history() + seq!(ne1@));
        assert(post2_netc.history() == pre_netc.history() + seq!(ne2@));
    }
}
